{
  "schema": "brainflow.proc_rule.v1",
  "name": "windows_cli_arglen_guard",
  "priority": 90,
  "when": {
    "os": "windows",
    "channel": "cli"
  },
  "rule": {
    "avoid_inline_args": true,
    "max_inline_arg_chars": 2000,
    "preferred_patterns": [
      "write payloads to temp files and pass file paths",
      "use config files for large JSON",
      "split large inputs across files"
    ],
    "fallback": "if inline args exceed limit, switch to file-based input or abort with a concise error"
  }
}
